import os

@tool
def validate_attachment(file_path: str) -> dict:
    """Validate attachment safety and type"""
    if not os.path.exists(file_path):
        return {"safe": False, "error": "File not found"}
    # Virus scan, type check logic
    return {"safe": True, "type": "pdf", "size": 102400}

attachment_agent = Agent(
    name="Attachment Handler",
    instructions="Ensure attachments are safe before processing",
    tools=[validate_attachment]
)

