from agents import Agent, tool

@tool
def validate_recipient(email: str) -> bool:
    """Check if recipient is authorized"""
    authorized_domains = ['company.com', 'partner.org']
    return any(domain in email for domain in authorized_domains)

approval_agent = Agent(
    name="Send Approval",
    instructions="ONLY approve safe, appropriate emails for sending",
