from vex import Vex
from agents import Runner

vex = Vex(api_key="your-vex-key")

def safe_agent_run(agent, input):
    result = runner.run_sync(agent, input)
    # Verify output before handoff
    verified = vex.verify_output(
        result.final_output,
        guardrails={
            'pii_filter': {'enabled': True},
            'tone_check': {'min_score': 0.8},
            'content_accuracy': {'enabled': True}
        }
    )
    if not verified.valid:
        raise ValueError(f"Guardrail failed: {verified.issues}")
    return result

