from vex import Vex

vex = Vex(api_key="your-vex-key")

# Apply to draft output
def check_pii_free(content: str) -> bool:
    verdict = vex.verify_output(
        content,
        guardrails={
            'pii_filter': {
                'enabled': True,
                'actions': ['ssn', 'email', 'phone'],
                'block_threshold': 0.9
            }
        }
    )
    return verdict.valid

# Before ApprovalAgent handoff
if not check_pii_free(draft):
    draft = vex.redact_pii(draft)
    print("PII redacted from draft")
